import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as h,o as s,c as k,a,d as r,b as t,f as m}from"./app-7cfa41e7.js";const o={},p=a("h2",{id:"摘抄",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#摘抄","aria-hidden":"true"},"#"),r(" 摘抄")],-1),l=a("hr",null,null,-1),c={href:"https://www.cnblogs.com/aspirant/p/8902285.html",target:"_blank",rel:"noopener noreferrer"},i=a("hr",null,null,-1),_={href:"https://www.cnblogs.com/aspirant/p/11470928.html",target:"_blank",rel:"noopener noreferrer"},d=m("<p>阿里的人问 数组的时间复杂度是多少，链表的是多少，hashmap的时间复杂度是多少。。。。。</p><p>后来才知道，时间复杂度是要区分 增删改查的。。。。主要看查询的时间复杂度；</p><p>1、数组 查询的时间复杂度 O(n)</p><p>2、链表 查询的时间复杂度 O(n)</p><p>3、hashmap 查询的时间复杂度 O(1)</p><p>数组 查询的时间复杂度 O(n)</p><p>建议看一下下面的博客：</p><p>hashSet,hashtable,hashMap 都是基于散列函数， 时间复杂度 O(1) 但是如果太差的话是O(n)</p><p>TreeSet==&gt;O(log(n))==&gt; 基于树的搜索，只需要搜索一半即可</p><p>O⑴的原因是离散后，下标对应关键字<br> hash就是散列，甚至再散列。但是我一直对hash表的时间复杂度有个疑问。一个需要存储的字符串，通过hash函数散列到一个相对较短的索引，使得存取速度加快。但为什么存取的时间复杂度能达到常量级O(1)呢？？ 查找时搜索索引不需要费时间吗？为什么不是O(n)呢？ n是hash表的长度,</p><p>如果对Hashtable的构造有很深的理解的话，就知道了，Hashtable 其实是综合了数组和链表的优点，当Hashtable对数值进行搜索的时候，首先用该数值与Hashtable的长度做了取模的操作，得到的数字直接作为hashtable中entry数组的index,因为hashtable是由entry数组组成的，因此，可以直接定位到指定的位置，不需要搜索，当然，这里还有个问题，每个entry其实是链表，如果entry有很多值的话，还是需要挨个遍历的，因此可以这样讲Hashtable的时间复杂度最好是O(1)但是最差是 O(n) 最差的时候也就是hashtable中所有的值的hash值都一样，都分配在一个entry里面，当然这个概率跟中1亿彩票的概率相差不大。</p><p>如果还不理解可以参考我写的专门的博客：</p>",12),b={href:"http://www.cnblogs.com/aspirant/p/8908399.html",target:"_blank",rel:"noopener noreferrer"},g={href:"http://www.cnblogs.com/aspirant/p/8906018.html",target:"_blank",rel:"noopener noreferrer"},f=m('<p>在看起来就是对Entry链表的循环的时间复杂度影响最大，链表查找的时间复杂度为O(n)，与链表长度有关。我们要保证那个链表长度为1，才可以说时间复杂度能满足O(1)。但这么说来只有那个hash算法尽量减少冲突，才能使链表长度尽可能短，理想状态为1。因此可以得出结论：HashMap的查找时间复杂度只有在最理想的情况下才会为O(1)，最差是O(n),而要保证这个理想状态不是我们开发者控制的。</p><p><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark><mark>开始</mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark></mark>=================</p><p>常用数据结构的时间复杂度</p><h3 id="常用数据结构的时间复杂度" tabindex="-1"><a class="header-anchor" href="#常用数据结构的时间复杂度" aria-hidden="true">#</a> 常用数据结构的时间复杂度</h3><hr><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/blog/image-20230511162933294.png" alt="image-20230511162933294" tabindex="0" loading="lazy"><figcaption>image-20230511162933294</figcaption></figure>',6);function u(O,w){const e=h("ExternalLinkIcon");return s(),k("div",null,[p,l,a("p",null,[r("原文链接："),a("a",c,[r("https://www.cnblogs.com/aspirant/p/8902285.html"),t(e)])]),i,a("p",null,[r("hashmap的扩容因子是0.75 原因 参考："),a("a",_,[r("HashMap默认加载因子为什么选择0.75？(阿里)"),t(e)])]),d,a("p",null,[r("关于HashMap的："),a("a",b,[r("HashMap的实现原理--链表散列"),t(e)])]),a("p",null,[r("关于Hashtable的："),a("a",g,[r("Hashtable数据存储结构-遍历规则，Hash类型的复杂度为啥都是O(1)-源码分析"),t(e)])]),f])}const y=n(o,[["render",u],["__file","Java集合时间复杂度.html.vue"]]);export{y as default};
